INSERT INTO `field_data_field_problem_statement` VALUES ('node','startup_idea',0,5,5,'und',0,'Many people struggle to find affordable and eco-friendly ride-sharing options in urban areas. Existing services are expensive or lack environmental considerations.',NULL),('node','startup_idea',0,6,6,'und',0,'Urban areas suffer from traffic congestion and high carbon emissions. Existing ride-sharing platforms do not optimize routes for environmental impact.',NULL),('node','startup_idea',0,7,7,'und',0,'Small hospitals lack secure and unified digital patient record systems, leading to data loss and inefficiency.',NULL),('node','startup_idea',0,8,8,'und',0,'Working professionals struggle to learn new skills due to lack of time and structured micro-learning platforms.',NULL),('node','startup_idea',0,9,9,'und',0,'Most grocery delivery platforms rely heavily on plastic packaging, increasing environmental waste.',NULL),('node','startup_idea',0,10,10,'und',0,'this is problem of statement',NULL),('node','startup_idea',0,11,11,'und',0,'5555',NULL),('node','startup_idea',0,12,12,'und',0,'xdgfxzcg',NULL),('node','startup_idea',0,14,14,'und',0,'rt',NULL);
