INSERT INTO `field_revision_field_solution_description` VALUES ('node','startup_idea',0,5,5,'und',0,'EcoRide provides a platform for carpooling with electric vehicles, using an AI-based route optimizer to reduce costs and emissions. Users can book rides, track environmental impact, and share rewards for green travel.',NULL),('node','startup_idea',0,6,6,'und',0,'EcoRide uses AI-driven route optimization to reduce fuel consumption and carbon emissions by 25% per ride.',NULL),('node','startup_idea',0,7,7,'und',0,'Blockchain-based medical record platform ensuring secure, tamper-proof storage and easy data sharing between clinics.',NULL),('node','startup_idea',0,8,8,'und',0,'Mobile app delivering 10-minute daily skill-building modules with AI-personalized learning paths.\r\nTarget Market\r\n\r\nYoung professionals aged 22–35.\r\n\r\nRevenue Model\r\n\r\nFreemium model + premium certification courses.\r\n\r\nImpact\r\n\r\nImproves career growth and skill accessibility.',NULL),('node','startup_idea',0,9,9,'und',0,'Zero-plastic packaging grocery delivery using reusable containers and electric vehicles.\r\n\r\nTarget Market\r\n\r\nEco-conscious households in metro cities.\r\n\r\nRevenue Model\r\n\r\nDelivery fees + membership plans.\r\n\r\nImpact\r\n\r\nReduces plastic waste and promotes sustainable consumption.',NULL),('node','startup_idea',0,11,11,'und',0,'errr',NULL),('node','startup_idea',0,12,12,'und',0,'xcbcvb',NULL),('node','startup_idea',0,14,14,'und',0,'rtyrt',NULL);
