DROP TABLE IF EXISTS `workflow_access`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_access` (
  `sid` int NOT NULL COMMENT 'The Workflow state ID.',
  `rid` int NOT NULL,
  `grant_view` tinyint unsigned NOT NULL DEFAULT '0',
  `grant_update` tinyint unsigned NOT NULL DEFAULT '0',
  `grant_delete` tinyint unsigned NOT NULL DEFAULT '0',
  PRIMARY KEY (`sid`,`rid`),
  KEY `rid` (`rid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COMMENT='Workflow access tables';
