DROP TABLE IF EXISTS `workflow_node`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_node` (
  `nid` int unsigned NOT NULL DEFAULT '0' COMMENT 'The `node`.nid this record is for.',
  `sid` int unsigned NOT NULL DEFAULT '0' COMMENT 'The `workflow_states`.sid that this node is currently in.',
  `uid` int unsigned NOT NULL DEFAULT '0' COMMENT 'The `users`.uid who triggered this state.',
  `stamp` int unsigned NOT NULL DEFAULT '0' COMMENT 'The unique stamp for the transition.',
