--

DROP TABLE IF EXISTS `workflow_node_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `workflow_node_history` (
  `hid` int NOT NULL AUTO_INCREMENT COMMENT 'The unique ID for this record.',
  `entity_type` varchar(255) NOT NULL DEFAULT '' COMMENT 'The type of entity this transition belongs to.',
  `nid` int unsigned NOT NULL DEFAULT '0' COMMENT 'The `node`.nid this record is for.',
  `revision_id` int unsigned DEFAULT NULL COMMENT 'The current version identifier.',
  `field_name` varchar(32) NOT NULL DEFAULT '' COMMENT 'The name of the field the transition relates to.',
  `language` varchar(32) NOT NULL DEFAULT '' COMMENT 'The `languages`.language of the entity.',
  `delta` int unsigned NOT NULL DEFAULT '0' COMMENT 'The sequence number for this data item, used for multi-value fields',
  `old_sid` int unsigned NOT NULL DEFAULT '0' COMMENT 'The `workflow_states`.sid this transition started as.',
  `sid` int unsigned NOT NULL DEFAULT '0' COMMENT 'The `workflow_states`.sid this transition transitioned to.',
  `uid` int unsigned NOT NULL DEFAULT '0' COMMENT 'The `users`.uid who made this transition.',
